import{_ as a,o as r,c as t,ag as n}from"./chunks/framework.DjqkqlVQ.js";const m=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/xuanji-character/faq.md","filePath":"en/mods/xuanji-character/faq.md","lastUpdated":1779001232000}'),o={name:"en/mods/xuanji-character/faq.md"};function i(s,e,d,c,h,l){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-kind-of-mod-is-xuanji" tabindex="-1">What kind of mod is Xuanji? <a class="header-anchor" href="#what-kind-of-mod-is-xuanji" aria-label="Permalink to &quot;What kind of mod is Xuanji?&quot;">​</a></h2><p>Xuanji is a custom character mod for Slay the Spire 2. He is built around Encode, the Machine Chamber, Machine Core condensing, and synergy progress. The mod adds a new character, custom cards, custom relics, and a different combat rhythm.</p><h2 id="is-the-current-version-ready-for-stable-play" tabindex="-1">Is the current version ready for stable play? <a class="header-anchor" href="#is-the-current-version-ready-for-stable-play" aria-label="Permalink to &quot;Is the current version ready for stable play?&quot;">​</a></h2><p>It is currently a Beta release. The core gameplay is playable, but balance, card distribution, UI details, and compatibility may continue to change.</p><h2 id="does-it-require-a-dependency" tabindex="-1">Does it require a dependency? <a class="header-anchor" href="#does-it-require-a-dependency" aria-label="Permalink to &quot;Does it require a dependency?&quot;">​</a></h2><p>Yes. Xuanji requires <code>BaseLib</code>.</p><h2 id="what-does-encode-mean" tabindex="-1">What does Encode mean? <a class="header-anchor" href="#what-does-encode-mean" aria-label="Permalink to &quot;What does Encode mean?&quot;">​</a></h2><p>Cards with Encode enter the Machine Chamber after being played. When the chamber reaches 3 cards, those cards condense into a Machine Core. Cards consumed by condensing will not contribute synergies again during the same combat.</p><h2 id="what-do-machine-cores-do" tabindex="-1">What do Machine Cores do? <a class="header-anchor" href="#what-do-machine-cores-do" aria-label="Permalink to &quot;What do Machine Cores do?&quot;">​</a></h2><p>Machine Cores provide synergy progress and a main Machine Core effect based on their main trait. For example, Bulwark cores lean defensive, Ambush cores support first-attack burst, and Overload cores support Energy.</p><h2 id="why-does-the-same-card-stop-contributing-synergies" tabindex="-1">Why does the same card stop contributing synergies? <a class="header-anchor" href="#why-does-the-same-card-stop-contributing-synergies" aria-label="Permalink to &quot;Why does the same card stop contributing synergies?&quot;">​</a></h2><p>That is a core constraint of the Encode system. After a card is consumed by condensing, it is treated as already encoded for that combat so one card cannot repeatedly farm synergy progress.</p><h2 id="where-can-i-see-the-exact-synergy-effects" tabindex="-1">Where can I see the exact synergy effects? <a class="header-anchor" href="#where-can-i-see-the-exact-synergy-effects" aria-label="Permalink to &quot;Where can I see the exact synergy effects?&quot;">​</a></h2><p>See <a href="/jasonsong-games/en/mods/xuanji-character/synergies">Synergy Details</a>. It lists each synergy&#39;s main Machine Core effect, thresholds, and tier effects.</p><h2 id="which-languages-are-supported" tabindex="-1">Which languages are supported? <a class="header-anchor" href="#which-languages-are-supported" aria-label="Permalink to &quot;Which languages are supported?&quot;">​</a></h2><p>English and Simplified Chinese are the primary maintained languages for now.</p><h2 id="can-it-be-used-with-other-mods" tabindex="-1">Can it be used with other mods? <a class="header-anchor" href="#can-it-be-used-with-other-mods" aria-label="Permalink to &quot;Can it be used with other mods?&quot;">​</a></h2><p>You can try, but Xuanji is a gameplay-affecting custom character mod. Other mods that change characters, card pools, relics, combat UI, BaseLib behavior, or internal game APIs may create compatibility risks.</p><h2 id="can-i-reupload-it-or-include-it-in-a-modpack" tabindex="-1">Can I reupload it or include it in a modpack? <a class="header-anchor" href="#can-i-reupload-it-or-include-it-in-a-modpack" aria-label="Permalink to &quot;Can I reupload it or include it in a modpack?&quot;">​</a></h2><p>Please do not reupload, redistribute modified builds, or include it in paid modpacks without permission.</p>',21)])])}const p=a(o,[["render",i]]);export{m as __pageData,p as default};
